Write a Python function that takes two lists of equal length and creates a dictionary of the elements in each list that have the same index. The function should also handle cases where the input lists are not of equal length and provide appropriate error handling. Additionally, the function should handle cases where the input lists contain nested lists or dictionaries, and create a dictionary of the nested elements at each index. The function should also handle cases where the input lists contain tuples and create a dictionary of the tuple elements at each index. The function should raise a ValueError if any element in the input lists is a set. 

list_one = [1, 2, [3, 4], {"a": "b"}, (7, 8), {9, 10}]
list_two = ["a", "b", [5, 6], {"c": "d"}, (11, 12), {13, 14}]

def create_index_dictionary(list_one, list_two):
    if len(list_one) != len(list_two):
        raise ValueError("Input lists must be of equal length")

    index_dict = {}
    for i in range(len(list_one)):
        if isinstance(list_one[i], (list, dict, tuple)) and isinstance(list_two[i], (list, dict, tuple)):
            if isinstance(list_one[i], set) or isinstance(list_two[i], set):
                raise ValueError("Input lists cannot contain sets")

            nested_dict = {}
            if isinstance(list_one[i], dict) and isinstance(list_two[i], dict):
                for key in list_one[i].keys():
                    nested_dict[key] = (list_one[i][key], list_two[i][key])
            elif isinstance(list_one[i], tuple) and isinstance(list_two[i], tuple):
                for j in range(len(list_one[i])):
                    nested_dict[j] = (list_one[i][j], list_two[i][j])

            index_dict[i] = nested_dict
        else:
            index_dict[i] = (list_one[i], list_two[i])

    return index_dict

