# Finding the difference between the largest and smallest prime numbers
def find_prime_difference(numbers):
    primes = []
    for num in numbers:
        if num > 1:
            for i in range(2, num):
                if (num % i) == 0:
                    break
            else:
                primes.append(num)

    if len(primes) > 1:
        return max(primes) - min(primes)
    else:
        return None

