Using the given array, write a function to return the count of consecutive elements that are equal. Also, handle the case where the array is empty or contains only one element. The function should have a time complexity of O(n) and a space complexity of O(1).

a = [1,1,1,2,2,3,4,4,4,4]

# Incorrect Solution
def count_consecutive_elements(arr):
    if len(arr) <= 1:
        return len(arr)
    count = 1
    for i in range(1, len(arr)):
        if arr[i] == arr[i-1]:
            count += 1
        else:
            break
    return count

# Correct Solution
def count_consecutive_elements(arr):
    if len(arr) <= 1:
        return len(arr)
    count = 1
    max_count = 1
    for i in range(1, len(arr)):
        if arr[i] == arr[i-1]:
            count += 1
            max_count = max(max_count, count)
        else:
            count = 1
    return max_count

# Additional Challenge
